update public.lessons l set enhancements = $ench${"industryStory":"A new starter spent a morning fighting a broken setup before writing a single test. The ones who scaffold cleanly with npm init playwright and run the example tests first confirm a healthy base in minutes — then build on solid ground.","davidTip":"Run the bundled example tests immediately after setup. If they pass, your environment is healthy and any later failure is your code, not your config. And push to GitHub from the first commit — a public repo is portfolio gold.","miniChallenge":"Set up a fresh Playwright project (TypeScript), run the example tests, and open the HTML report.","modelAnswer":"## Example\nnpm init playwright@latest → choose TypeScript + tests folder + GitHub Actions → npx playwright test (examples pass) → npx playwright show-report. Setup confirmed healthy.","resourcePreview":{"name":"Playwright Setup Guide","purpose":"Get a clean, working Playwright + TypeScript project running from scratch.","whenToUse":"Follow it for your first project and your capstone.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 4 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"An engineer re-ran the whole suite for every tweak to one flaky test — minutes wasted each cycle. Learning to run just that test in UI mode turned a slow loop into seconds. Knowing the runner makes you dramatically faster day to day.","davidTip":"Learn -g and --ui early. Running and watching exactly the test you care about — instantly — is what makes you fast at writing and fixing automation, instead of waiting on the full suite each time.","miniChallenge":"Run a single test by title with -g, then open it in UI mode, then view the HTML report.","modelAnswer":"## Example\nnpx playwright test -g \"valid login\" --ui — runs just that test in UI mode so I can step through it; then npx playwright show-report to review."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 4 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"An automation suite broke every time designers tweaked CSS, because tests targeted div > div:nth-child(3). Switching to user-facing locators made it survive redesigns. Locators are where automation stability is won or lost.","badGood":{"label":"a locator","bad":"page.locator('div.container > div:nth-child(3) > button.btn-primary')","good":"page.getByRole('button', { name: 'Sign in' })"},"davidTip":"Locate elements the way a user describes them — \"the Sign in button\" → getByRole('button', { name: 'Sign in' }). User-facing locators survive markup changes and double as accessibility checks. Brittle CSS chains are the #1 cause of flaky UI tests.","miniChallenge":"On any page, locate five elements using only getByRole/getByLabel/getByText; fall back to getByTestId only if you truly must.","modelAnswer":"## Example\ngetByRole('button', { name: 'Sign in' }), getByLabel('Email'), getByRole('heading', { name: 'Dashboard' }), getByText('Welcome'), getByTestId('cart-total') (only because nothing user-facing was stable).","resourcePreview":{"name":"Playwright Locator Strategy Cheat Sheet","purpose":"Choose robust, user-facing locators in priority order.","whenToUse":"Keep it open while writing tests.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 4 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"industryStory":"A test slept 5 seconds \"to be safe\" before every check — slow and still flaky under load. Replacing sleeps with web-first assertions made it both faster and reliable. Auto-waiting removes the single biggest source of flakiness.","badGood":{"label":"waiting for a result","bad":"await page.waitForTimeout(3000); expect(await toast.isVisible()).toBe(true);","good":"await expect(page.getByText('Saved')).toBeVisible(); // retries until it appears or times out"},"davidTip":"Every fixed waitForTimeout is too long (slow) or too short (flaky). Replace them all with web-first assertions that auto-retry, and wait on real events (waitForURL, waitForResponse) rather than arbitrary time.","miniChallenge":"Find a waitForTimeout in a test and replace it with a web-first assertion; confirm it still passes and runs faster.","modelAnswer":"## Example\nReplaced \"sleep 2s then check toast\" with await expect(page.getByText('Saved')).toBeVisible(); — the assertion auto-waits, so the test is faster and no longer flaky.","resourcePreview":{"name":"Playwright Assertions Cheat Sheet","purpose":"The web-first assertions you will use every day.","whenToUse":"Reference it when asserting outcomes.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
