where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 4 and l.lesson_number = 5;

update public.lessons l set enhancements = $ench${"industryStory":"A CI test failed and the engineer guessed for an hour. Once they enabled traces and opened the trace viewer, the cause — a click before the element was ready — was obvious in seconds. The trace viewer is Playwright's superpower.","davidTip":"Before changing any code to fix a failure, open the trace. The trace viewer shows every action with before/after snapshots, network and console — it usually reveals the cause immediately. Enable trace on-first-retry in CI.","miniChallenge":"Deliberately break a locator, run with traces on, open the trace and identify exactly where and why it failed.","modelAnswer":"## Example\nThe trace showed the click fired before the button was attached/visible; I added the correct web-first assertion (or fixed the locator) and the trace confirmed the action then succeeded.","portfolioBuilder":"Mentioning trace-driven debugging in your capstone README (and CI artifacts) shows you can diagnose failures like a professional, not just write happy-path tests.","resourcePreview":{"name":"Debugging & Trace Viewer Guide","purpose":"Diagnose failures fast with Playwright’s debugging tools.","whenToUse":"Use it whenever a test fails and the cause is unclear.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
